import { Box, Paper, Typography } from '@mui/material';
import { alpha } from '@mui/material/styles';
import {
  Chart as ChartJS,
  ChartType,
  Legend,
  LinearScale,
  PointElement,
  Title,
  Tooltip,
  TooltipModel,
} from 'chart.js';
import React, {
  Dispatch,
  FC,
  SetStateAction,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { Scatter } from 'react-chartjs-2';

import {
  BallParamField,
  BallParamFieldParam,
} from '@/components/sessions/ball-param-icon';
import useServicesHook from '@/hooks';
import { Ball } from '@/models/ball';
import { PitchType } from '@/models/pitch-type';
import { Resource } from '@/models/resource';
import { useSelector } from '@/store';
import { translate, TranslationKey } from '@/utils/i18n';

import { CommonModal } from '../common-modal';
import { PitchTypeStats, PitchTypeTable } from './pitch-type-table';

ChartJS.register(LinearScale, PointElement, Tooltip, Legend, Title);

type DataPoint = { x: number; y: number; pitchTypeId: string; ballId: number };

function isDataPoint(obj: unknown): obj is DataPoint {
  return (
    typeof obj === 'object' &&
    obj !== null &&
    typeof (obj as any).x === 'number' &&
    typeof (obj as any).y === 'number' &&
    typeof (obj as any).pitchTypeId === 'string' &&
    typeof (obj as any).ballId === 'number'
  );
}

export type ScatterModalParam = {
  isOpen: boolean;
  onClose?: Function;
  setIsOpen: Dispatch<SetStateAction<boolean>>;
  title?: string;
  teamId: string;
  sessionId: string;
};

export const ScatterModal: FC<ScatterModalParam> = ({
  isOpen,
  onClose,
  setIsOpen,
  title,
  teamId,
  sessionId,
}) => {
  const { services } = useServicesHook();

  const unit = useSelector((state) => state.user.unit);
  const pitchTypes = useSelector((state) => state.master.pitchTypes);
  const defaultColor = 'rgba(160, 160, 160, 0.8)';
  const pitchTypeToColor = {
    // fastball
    '4_seam_fastball': 'rgba(210, 45, 73, 0.8)',
    cutter: 'rgba(147, 63, 45, 0.8)',
    sinker: 'rgba(254, 157, 0.8)',
    // vertical
    changeup: 'rgba(28, 190, 59, 0.8)',
    forkball: 'rgba(85, 204, 171, 0.8)',
    splitter: 'rgba(60, 172, 172, 0.8)',
    // dialognal
    curveball: 'rgba(1, 209, 237, 0.8)',
    knuckle_curve: 'rgba(98, 54, 205, 0.8)',
    screwball: 'rgba(96, 219, 51, 0.8)',
    slurve: 'rgba(147, 175, 212, 0.8)',
    // horizontal
    slider: 'rgba(238, 231, 23, 0.8)',
    sweeper: 'rgba(221, 179, 58, 0.8)',
    // others
    eephus: 'rgba(136, 136, 136, 0.8)',
    knuckleball: 'rgba(61, 68, 205, 0.8)',
  };
  const pitchTypeIdToPitchType = pitchTypes.reduce<Record<string, PitchType>>(
    (acc, pitchType) => {
      acc[pitchType.id] = pitchType;
      return acc;
    },
    {},
  );
  const pitchTypeIdToColor = pitchTypes.reduce<Record<string, string>>(
    (acc, pitchType) => {
      acc[pitchType.id] =
        pitchTypeToColor[
          pitchType.pitchType! as keyof typeof pitchTypeToColor
        ] ?? defaultColor;
      return acc;
    },
    {},
  );

  const [_, setIsInitialized] = useState<boolean>(false);
  const [resources, setResources] = useState<Resource[]>([]);
  const [ballsMap, setBallsMap] = useState<Record<number, Ball>>({});
  const [tooltipBallId, setTooltipBallId] = useState<number | null>(null);

  const getResources = async (teamId: string, sessionId: string) => {
    const result = await services.default.resource.getResources(
      teamId,
      sessionId,
      {
        dateFilter: 'all',
        offset: 0,
        pageSize: 1000,
      },
    );
    if (result.error) {
      // TODO
      return;
    }
    setResources(result.resources);
    setBallsMap(
      result.resources.reduce<Record<number, Ball>>((acc, resource) => {
        resource.ballInfoList.forEach((ballInfo) => {
          acc[ballInfo.ball.id] = ballInfo.ball;
        });
        return acc;
      }, {}),
    );
  };

  const initialize = async () => {
    try {
      await Promise.all([getResources(teamId, sessionId)]);
    } finally {
      setIsInitialized(true);
    }
  };

  useEffect(() => {
