        sx={{
          position: 'absolute',
          left: dataPoint.x < 0 ? '60%' : '25%', // 座標上のデータの位置を基準にしてTooltipを配置
          top: '15%',
          width: 'fit-content',
          height: 'fit-content',
          backgroundColor: (theme) =>
            alpha(theme.palette.background.paper, 0.92),
          p: 1.5,
          borderRadius: '8px',
          zIndex: (theme) => theme.zIndex.tooltip,
          pointerEvents: 'none',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'space-around',
        }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Box
            sx={{
              width: '0.75rem',
              height: '0.75rem',
              borderRadius: '3px',
              backgroundColor:
                pitchTypeIdToColor[dataPoint.pitchTypeId] ?? defaultColor,
            }}
          />
          <Typography variant="caption" fontWeight="bold" noWrap>
            {translate(
              `pitch_type_${pitchTypeIdToPitchType[dataPoint.pitchTypeId]?.pitchType}` as TranslationKey,
            ) ?? ''}
          </Typography>
        </Box>

        <Box sx={{ mt: 1, mb: 1 }}>
          {displayItems.map((item) => (
            <Box sx={{ mb: 1 }} key={`param-${item.type}`}>
              <BallParamField
                type={item.type}
                value={item.value}
                iconSize="1.2rem"
                fontSize="0.75rem"
              />
            </Box>
          ))}
        </Box>
      </Paper>
    );
  };

  return (
    <CommonModal
      isOpen={isOpen}
      onClose={onClose}
      setIsOpen={setIsOpen}
      renderContent={(preferredSize) => {
        const preferredScatterSize = Math.min(
          preferredSize.width,
          // There is also space for the title, so to ensure some margin
          preferredSize.height - 8,
          500,
        );

        return (
          <>
            {title && (
              <Typography variant="h4" gutterBottom>
                {title}
              </Typography>
            )}

            <Box
              sx={{
                position: 'relative',
                width: preferredScatterSize,
                height: preferredScatterSize,
                ml: 'auto',
                mr: 'auto',
              }}
            >
              <Scatter data={chartData} options={options} />

              {tooltipBallId !== null && (
                <BallTooltip
                  ball={ballsMap[tooltipBallId]}
                  dataPoint={ballIdDataMap[tooltipBallId]}
                />
              )}
            </Box>

            <Box
              sx={{
                mt: 3,
                ml: 'auto',
                mr: 'auto',
                width: preferredScatterSize,
              }}
            >
              <PitchTypeTable
                stats={pitchTypeStats}
                pitchTypes={pitchTypeIdToPitchType}
                colors={pitchTypeIdToColor}
                unit={unit}
              />
            </Box>
          </>
        );
      }}
    />
  );
};
